20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	};
27	
28	const FIRST_INSURANCE_RATE = 0.1;
29	const CURSE_RATE = 0.5;
30	const HIGH_ENCH_RATE = 0.3;
31	const HIGH_ENCH_THRESHOLD = 5;
32	const LOYALTY_RATE = 0.2;
33	const LOYALTY_THRESHOLD = 2;
34	const FOLLOWUP_RATE = 0.15;
35	const PROCESSING_FEE = 5;
36	
37	const COMPONENT_PREMIUM = 25;
38	const BLOCK_SIZE = 3;
39	const BLOCK_PREMIUM = 60;
40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	
42	const componentBasePremium = (count: number): number =>
43	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
44	
45	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
46	
47	const isMainItem = (item: Item): boolean => !isComponent(item);
48	
49	const countByType = (items: Item[]): Map<string, number> =>
50	  items.reduce(
51	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
52	    new Map<string, number>(),
53	  );
54	
55	const componentTotal = (items: Item[]): number =>
56	  [...countByType(items.filter(isComponent)).values()].reduce(
57	    (sum, count) => sum + componentBasePremium(count),
58	    0,
59	  );
60	
61	const basePremium = (items: Item[]): number => {
62	  const mainTotal = items
63	    .filter(isMainItem)
64	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
65	  return mainTotal + componentTotal(items);
66	};
67	
68	const mainItemBase = (item: Item): number => BASE_PREMIUM[item.type];
69	
70	const surchargeFor = (
71	  items: Item[],
72	  qualifies: (item: Item) => boolean,
73	  rate: number,
74	): number =>
75	  items
76	    .filter((item) => isMainItem(item) && qualifies(item))
77	    .reduce((sum, item) => sum + mainItemBase(item) * rate, 0);
78	
79	const isCursed = (item: Item): boolean => item.cursed === true;
80	
81	const curseSurcharge = (items: Item[]): number =>
82	  surchargeFor(items, isCursed, CURSE_RATE);
83	
84	const isHighlyEnchanted = (item: Item): boolean =>
85	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
86	
87	const highEnchantmentSurcharge = (items: Item[]): number =>
88	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCH_RATE);
89	
90	const loyaltyDiscount = (policyBase: number, years: number): number =>
91	  years >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
92	
93	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
94	  isFollowUp ? policyBase * FOLLOWUP_RATE : 0;
95	
96	const quotePremium = (items: Item[], years: number, isFollowUp: boolean): number => {
97	  const policyBase = basePremium(items);
98	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
99	  const itemSurcharges = curseSurcharge(items) + highEnchantmentSurcharge(items);
100	  const loyalty = loyaltyDiscount(policyBase, years);
101	  const followUp = followUpDiscount(policyBase, isFollowUp);
102	  return Math.ceil(
103	    policyBase + itemSurcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE,
104	  );
105	};
