107	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
108	  const years = scenario.customer.yearsWithMHPCO;
109	  const results = scenario.steps.map((step, index) => ({
110	    premium: quotePremium(step.items, years, index > 0),
111	  }));
112	  return { results };
113	};
